import React from 'react';
import { render } from '@testing-library/react';
import Header from '../../src/components/global-header/index.js';

describe('Global Header', () => {
  it('renders the header with correct text and navigation links', () => {
    const { getByText, getByRole } = render(<Header />);
    expect(getByText(/Raj chavda the developer/i)).toBeInTheDocument();
    expect(getByRole('link', { name: /Shop/i })).toBeInTheDocument();
    expect(getByRole('link', { name: /Categories/i })).toBeInTheDocument();
    expect(getByRole('link', { name: /Search/i })).toBeInTheDocument();
  });
});

