import React from 'react';
import { render, screen } from '@testing-library/react';
import Footer from '../src/components/Footer/index.js';

describe('Footer Component', () => {
  it('should remove text and display new content in the footer', () => {
    render(<Footer />);
    expect(screen.queryByText(/Add us on social media?/i)).not.toBeInTheDocument();
    expect(screen.getByText(/Raj chavda/i)).toBeInTheDocument();
  });

  it('should not cause layout distortion or text overflow', () => {
    render(<Footer />);
    const footerElement = screen.getByRole('footer');
    expect(footerElement).toHaveStyle('text-overflow: clip;');
    expect(footerElement).toHaveStyle('white-space: nowrap;');
  });

  it('should match the original design requirements for Raj chavda styling', () => {
    render(<Footer />);
    const rajChavdaText = screen.getByText(/Raj chavda/i);
    expect(rajChavdaText).toHaveStyle('font-size: 16px;');
    expect(rajChavdaText).toHaveStyle('color: #333;');
    expect(rajChavdaText).toHaveStyle('text-align: center;');
  });
});
